#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Node Structure for Trie
typedef struct Node {
    struct Node* links[26];
    int flag;
} Node;

// Function to create a new node
Node* createNode() {
    Node* newNode = (Node*) malloc(sizeof(Node));
    for (int i = 0; i < 26; i++) {
        newNode->links[i] = NULL;
    }
    newNode->flag = 0;
    return newNode;
}

// Trie class
typedef struct Trie {
    Node* root;
} Trie;

// Function to initialize the Trie
Trie* initTrie() {
    Trie* trie = (Trie*) malloc(sizeof(Trie));
    trie->root = createNode();
    return trie;
}

// Function to insert a word into the Trie
void insert(Trie* trie, char* word) {
    Node* node = trie->root;
    for (int i = 0; i < strlen(word); i++) {
        if (node->links[word[i] - 'a'] == NULL) {
            node->links[word[i] - 'a'] = createNode();
        }
        node = node->links[word[i] - 'a'];
    }
    node->flag = 1;
}

// Function to search for a word in the Trie
int search(Trie* trie, char* word) {
    Node* node = trie->root;
    for (int i = 0; i < strlen(word); i++) {
        if (node->links[word[i] - 'a'] == NULL) {
            return 0;
        }
        node = node->links[word[i] - 'a'];
    }
    return node->flag;
}

// Function to check if there is any word in the Trie that starts with the given prefix
int startsWith(Trie* trie, char* prefix) {
    Node* node = trie->root;
    for (int i = 0; i < strlen(prefix); i++) {
        if (node->links[prefix[i] - 'a'] == NULL) {
            return 0;
        }
        node = node->links[prefix[i] - 'a'];
    }
    return 1;
}

int main() {
    // Test the Trie
    Trie* trie = initTrie();
    insert(trie, "apple");
    printf("%d\n", search(trie, "apple"));  // Output: 1
    printf("%d\n", startsWith(trie, "app"));  // Output: 1
    return 0;
}

